function getBalcony(uint256 _tokenId) public pure returns (string memory) {
    require(_tokenId > 0 && _tokenId < 8009, "Token ID invalid");
    if (hasBalcony(_tokenId)) {
      return "Balcony";
    } else {
      return "No Balcony";
    }
  }

function withdraw(address asset) onlyOwner public {
        if (asset == address(0)) {
            msg.sender.transfer(address(this).balance);
        } else {
            IERC20 token = IERC20(asset);
            token.safeTransfer(msg.sender, token.balanceOf(address(this)));
        }
    }

function cloneRebalancer(address _providerA, address _providerB, address _governance, address _strategist, address _bpt) external returns (address newStrategy) {
        bytes20 addressBytes = bytes20(address(this));

        assembly {
        // EIP-1167 bytecode
            let clone_code := mload(0x40)
            mstore(clone_code, 0x3d602d80600a3d3981f3363d3d373d3d3d363d73000000000000000000000000)
            mstore(add(clone_code, 0x14), addressBytes)
            mstore(add(clone_code, 0x28), 0x5af43d82803e903d91602b57fd5bf30000000000000000000000000000000000)
            newStrategy := create(0, clone_code, 0x37)
        }

        Rebalancer(newStrategy).initialize(_providerA, _providerB, _governance, _strategist, _bpt);

        emit Cloned(newStrategy);
    }

function reveal(string memory base) public onlyOwner {
        require(
            mutableMetadata, // Check to make sure the collection hasn't been frozen before allowing the metadata to change
            "Metadata is frozen on the blockchain forever"
        );
        baseURI = base;
        emit executedReveal(tokenCounter - revealedMechs);
        revealedMechs = tokenCounter;
    }

function notifyRewardAmount(uint256 reward)
        external
        onlyRewardDistribution
        updateReward(address(0))
    {
        if (block.timestamp > starttime) {
            if (block.timestamp >= periodFinish) {
                rewardRate = reward.div(DURATION);
            } else {
                uint256 remaining = periodFinish.sub(block.timestamp);
                uint256 leftover = remaining.mul(rewardRate);
                rewardRate = reward.add(leftover).div(DURATION);
            }
            lastUpdateTime = block.timestamp;
            periodFinish = block.timestamp.add(DURATION);
            emit RewardAdded(reward);
        } else {
            rewardRate = reward.div(DURATION);
            lastUpdateTime = starttime;
            periodFinish = starttime.add(DURATION);
            emit RewardAdded(reward);
        }
    }

